import { APIGatewayEvent, Context, APIGatewayProxyResult } from 'aws-lambda';
import { DynamoDBClient, PutItemCommand } from "@aws-sdk/client-dynamodb";

const dynamoDb = new DynamoDBClient({ region: process.env.AWS_REGION });
const tableName = process.env.USER_TABLE;

export async function handler(event: APIGatewayEvent, context: Context): Promise<APIGatewayProxyResult> {
    const body = JSON.parse(event.body);
    const email = body.email;
    const password = body.password;

    // Simplified DynamoDB Item structure. Replace with actual schema.
    const item = {
        Email: email,
        Password: password,
    };

    try {
        await dynamoDb.send(new PutItemCommand({ TableName: tableName, Item: item }));
        return { statusCode: 201, body: JSON.stringify({ message: 'User created successfully' }) };
    } catch (error) {
        console.error(error);
        return { statusCode: 500, body: JSON.stringify({ error: 'An error occurred while creating the user' }) };
    }
}